<?php require_once __DIR__.'/../../config/app.php'; requireAuth(); $pageTitle='Notices'; if(isset($_GET['delete'])){executeSql('DELETE FROM notices WHERE id=?',[(int)$_GET['delete']]); header('Location:index.php'); exit;} if($_SERVER['REQUEST_METHOD']==='POST'){verifyCsrf(); executeSql('INSERT INTO notices(title,content,audience,publish_at) VALUES (?,?,?,?)',[post('title'),post('content'),post('audience','All'),post('publish_at')]); header('Location:index.php'); exit;} $rows=fetchAll('SELECT * FROM notices ORDER BY publish_at DESC'); include __DIR__.'/../../includes/header.php'; include __DIR__.'/../../includes/sidebar.php'; ?><main class="content-wrap"><?php include __DIR__.'/../../includes/topbar.php'; ?><section class="panel glass"><form method="post" class="row g-2"><?=csrfField()?><div class="col"><input name="title" class="form-control" placeholder="Title"></div><div class="col"><input name="content" class="form-control" placeholder="Content"></div><div class="col"><select name="audience" class="form-select"><option>All</option><option>Students</option><option>Faculty</option><option>Staff</option></select></div><div class="col"><input type="datetime-local" name="publish_at" class="form-control" value="<?=date('Y-m-d\TH:i')?>"></div><div class="col"><button class="btn btn-primary">Publish</button></div></form><hr><table class="table"><?php foreach($rows as $r):?><tr><td><?=e($r['title'])?></td><td><?=e($r['audience'])?></td><td><?=$r['publish_at']?></td><td><a href="?delete=<?=$r['id']?>" onclick="return confirm('Delete?')">Delete</a></td></tr><?php endforeach;?></table></section></main><?php include __DIR__.'/../../includes/footer.php'; ?>
